import{_ as a,c as e,a as n,o as i}from"./app-6Yjp8K1A.js";const l={};function r(p,s){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="解决-npm-err-code-cert-has-expired-错误" tabindex="-1"><a class="header-anchor" href="#解决-npm-err-code-cert-has-expired-错误"><span>解决 npm ERR! code CERT_HAS_EXPIRED 错误</span></a></h1><p>在使用 npm 安装 Vue 项目依赖时，可能会遇到 <code>npm ERR! code CERT_HAS_EXPIRED</code> 错误。该错误是由于请求淘宝 npm 镜像时，证书已过期导致的。以下是几种解决方法：</p><h2 id="_1-问题描述" tabindex="-1"><a class="header-anchor" href="#_1-问题描述"><span>1. 问题描述</span></a></h2><p>在运行 <code>npm install</code> 命令时，可能会出现以下错误信息：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">npm ERR! code CERT_HAS_EXPIRED</span>
<span class="line">npm ERR! errno CERT_HAS_EXPIRED</span>
<span class="line">npm ERR! request to https://registry.npm.taobao.org/vue-loader failed, reason: certificate has expired</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这表明请求淘宝 npm 镜像时，证书已过期，导致请求失败。</p><h2 id="_2-解决方案" tabindex="-1"><a class="header-anchor" href="#_2-解决方案"><span>2. 解决方案</span></a></h2><h3 id="_2-1-切换镜像源" tabindex="-1"><a class="header-anchor" href="#_2-1-切换镜像源"><span>2.1 切换镜像源</span></a></h3><h4 id="_2-1-1-切回官方-npm-源" tabindex="-1"><a class="header-anchor" href="#_2-1-1-切回官方-npm-源"><span>2.1.1 切回官方 npm 源</span></a></h4><p>运行以下命令切换到官方 npm 源：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config <span class="token builtin class-name">set</span> registry https://registry.npmjs.org/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>验证是否切换成功：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config get registry</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果输出 <code>https://registry.npmjs.org/</code>，则表示设置成功。</p><h4 id="_2-1-2-换其他稳定镜像" tabindex="-1"><a class="header-anchor" href="#_2-1-2-换其他稳定镜像"><span>2.1.2 换其他稳定镜像</span></a></h4><p>如果想继续使用国内镜像，可以尝试阿里云的 npm 镜像：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config <span class="token builtin class-name">set</span> registry https://registry.npmmirror.com/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>验证是否切换成功：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config get registry</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果输出 <code>https://registry.npmmirror.com/</code>，则表示设置成功。</p><h3 id="_2-2-更新-npm" tabindex="-1"><a class="header-anchor" href="#_2-2-更新-npm"><span>2.2 更新 npm</span></a></h3><p>旧版本的 npm 可能存在 SSL 证书兼容问题，建议更新 npm 到最新版本：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> <span class="token function">install</span> <span class="token parameter variable">-g</span> <span class="token function">npm</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_2-3-临时绕过-ssl-验证" tabindex="-1"><a class="header-anchor" href="#_2-3-临时绕过-ssl-验证"><span>2.3 临时绕过 SSL 验证</span></a></h3><p>如果问题仍未解决，可以临时关闭严格 SSL 检查：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config <span class="token builtin class-name">set</span> strict-ssl <span class="token boolean">false</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>但请注意，这会降低安全性。问题解决后，建议恢复安全验证：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> config <span class="token builtin class-name">set</span> strict-ssl <span class="token boolean">true</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_2-4-清理缓存" tabindex="-1"><a class="header-anchor" href="#_2-4-清理缓存"><span>2.4 清理缓存</span></a></h3><p>清理 npm 缓存，可能会解决因缓存导致的问题：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">npm</span> cache clean <span class="token parameter variable">--force</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_2-5-检查系统时间" tabindex="-1"><a class="header-anchor" href="#_2-5-检查系统时间"><span>2.5 检查系统时间</span></a></h3><p>系统时间不准确可能导致证书校验失败。请确保系统时间与网络时间一致：</p><ol><li>进入系统设置。</li><li>确保“自动同步时间”已开启。</li></ol><h2 id="_3-总结" tabindex="-1"><a class="header-anchor" href="#_3-总结"><span>3. 总结</span></a></h2><p>优先推荐切换镜像源，因为这是最直接且安全的解决方案。如果问题仍未解决，可以尝试其他方法，但请注意安全性和兼容性。</p><p>希望以上方法能帮助您解决问题！</p>`,37)])])}const c=a(l,[["render",r]]),d=JSON.parse('{"path":"/%E5%89%8D%E7%AB%AF%E6%8A%80%E6%9C%AF/%E5%B7%A5%E7%A8%8B%E5%8C%96/npm%E9%97%AE%E9%A2%98.html","title":"解决 npm ERR! code CERT_HAS_EXPIRED 错误","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773394873000,"contributors":[{"name":"wulr","username":"wulr","email":"wulr@eastcom-sw.com","commits":1,"url":"https://github.com/wulr"}],"changelog":[{"hash":"2e05be3a6e915f9542c6b5a3b229ee576fde38ba","time":1773394873000,"email":"wulr@eastcom-sw.com","author":"wulr","message":"Remove spaces from MD filenames and update references"}]},"filePathRelative":"前端技术/工程化/npm问题.md"}');export{c as comp,d as data};
